// Bumped from v1: the fetch handler below now caches the JS bundle, so the old
// cache's contents are no longer what this worker expects to find.
const CACHE_NAME = "ikigai-static-v2";

// Only cache true static assets — never HTML pages or authenticated routes.
// Deliberately does NOT include /manifest.webmanifest: that is generated by
// app/manifest.ts, so it's a route rather than a file, and cache.addAll()
// rejects as a unit — one bad response and the install fails, silently, taking
// push notifications and everything else in this worker down with it.
const STATIC_ASSETS = ["/icon-192x192.png", "/icon-512x512.png"];

self.addEventListener("install", (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) =>
      // Per-asset, not addAll: a single failure shouldn't abort the install.
      Promise.all(
        STATIC_ASSETS.map((asset) => cache.add(asset).catch(() => {})),
      ),
    ),
  );
  // Do NOT skipWaiting — let the SW activate on the next navigation
  // so it never takes control of a page mid-session and confuses the router
});

self.addEventListener("activate", (event) => {
  event.waitUntil(
    caches
      .keys()
      .then((keys) =>
        Promise.all(
          keys.filter((k) => k !== CACHE_NAME).map((k) => caches.delete(k)),
        ),
      ),
  );
  // Do NOT clients.claim() — avoids intercepting pages that are already loaded
});

self.addEventListener("fetch", (event) => {
  if (event.request.method !== "GET") return;

  const url = new URL(event.request.url);

  // Never intercept navigation requests — let Next.js handle all HTML pages
  if (event.request.mode === "navigate") return;

  // Only serve from cache for same-origin static assets
  if (url.origin !== self.location.origin) return;

  // The build output: JS chunks, CSS and fonts.
  //
  // This is the whole point of shipping a PWA and it was missing. Nothing under
  // /_next/static was cached, so every visit re-downloaded the entire bundle —
  // well over a megabyte — on connections where that is slow and metered. The
  // RSC and chunk requests that carry it aren't navigations, so the bailout
  // above never covered them; they simply fell through to a STATIC_ASSETS list
  // they were never in, and hit the network every time.
  //
  // Cache-first is safe here specifically because these paths are content
  // hashed and immutable: a new build produces new filenames, so a cached entry
  // can never be a stale version of current code. That is the staleness worry
  // the navigate bailout exists for, and it does not apply to this prefix.
  if (url.pathname.startsWith("/_next/static/")) {
    event.respondWith(
      caches.open(CACHE_NAME).then(async (cache) => {
        const hit = await cache.match(event.request);
        if (hit) return hit;
        const response = await fetch(event.request);
        // Only store a real success. An opaque or errored response cached here
        // would be served back as a broken chunk forever.
        if (response.ok) cache.put(event.request, response.clone());
        return response;
      }),
    );
    return;
  }

  // Cache-first for known static assets; network-only for everything else
  if (STATIC_ASSETS.includes(url.pathname)) {
    event.respondWith(
      caches
        .match(event.request)
        .then((cached) => cached ?? fetch(event.request)),
    );
  }
});

self.addEventListener("push", (event) => {
  if (!event.data) return;
  const data = event.data.json();
  event.waitUntil(
    self.registration.showNotification(data.title ?? "Ikigai", {
      body: data.body ?? "",
      icon: data.icon ?? "/icon-192x192.png",
      badge: "/icon-192x192.png",
      vibrate: [100, 50, 100],
      data: { url: data.url ?? "/dashboard" },
    }),
  );
});

self.addEventListener("notificationclick", (event) => {
  event.notification.close();
  const target = event.notification.data?.url ?? "/dashboard";
  event.waitUntil(
    clients
      .matchAll({ type: "window", includeUncontrolled: true })
      .then((wins) => {
        const existing = wins.find((w) => w.url.includes(target));
        if (existing) return existing.focus();
        return clients.openWindow(target);
      }),
  );
});
